import React from "react";

function Home() {
  const displayname = localStorage.getItem("name") || "User";

  return (
    <>
      <div className="container">
        <h2 className="p-5">Welcome, {displayname} to My Portfolio</h2>
        <div className="row">
          <div className="col-md-6">
            <h1 className="mt-5">Hello, My name is Prathmesh Nalawade</h1>
            <p>I'm BCS Graduate Student,</p>
            <p>I certified in Full MERN Stack Web Development.</p>
            <p>
              React.js •{" "}
              Node.js •{" "}
              Express.js •{" "}
              MongoDB
            </p>
          </div>
          <div className="col-md-6">
            <img
              src="/assets/profilephoto.png"
              alt="Profile"
              className="img-fluid"
            ></img>
          </div>
        </div>
      </div>
    </>
  );
}

export default Home;
